import mujoco,numpy as np,time
from eval import simulate_model
base=open('model_ref.xml').read()
def state(m,seed):
    d=mujoco.MjData(m); rng=np.random.default_rng(seed); d.qpos+=rng.normal(0,0.01,size=d.qpos.shape)
    mujoco.mj_forward(m,d)
    for i in range(int(2.0/m.opt.timestep)): mujoco.mj_step(m,d)
    st=np.zeros(mujoco.mj_stateSize(m,mujoco.mjtState.mjSTATE_FULLPHYSICS))
    mujoco.mj_getState(m,d,st,mujoco.mjtState.mjSTATE_FULLPHYSICS); return st
def mk(o,f):
    open(f,'w').write(base.replace('  <compiler autolimits=\"true\"/>\n','  <compiler autolimits=\"true\"/>\n  <option '+o+'/>\n'))
    return mujoco.MjModel.from_xml_path(f)
mr=mujoco.MjModel.from_xml_path('model_ref.xml')
cfgs={'ref':mr,
 'PGS_sparse':mk('solver=\"PGS\" jacobian=\"sparse\"','/tmp/c.xml'),
 'PGS_dense':mk('solver=\"PGS\" jacobian=\"dense\"','/tmp/d.xml')}
# robustness
for k,m in cfgs.items():
    if k=='ref':continue
    mx=max(np.max(np.abs(state(m,sd)-state(mr,sd))) for sd in range(30))
    print(k,'max elementwise diff over 30 seeds',mx)
acc={k:[] for k in cfgs}
for r in range(60):
    for k,m in cfgs.items():
        s=np.random.randint(0,10000)
        t0=time.perf_counter(); simulate_model(m,s); acc[k].append(time.perf_counter()-t0)
rm=np.mean(acc['ref'])
for k in cfgs: print(k, round(np.mean(acc[k])/rm,3))
